import type { Placement } from '@floating-ui/react';
import type React from 'react';

import type { TestComponentProps } from '../../types/test-component';
import type { TextFieldProps } from '../TextField';

type TextFieldPropsOmit = Omit<TextFieldProps, 'onChange' | 'value'>;

export interface Option<T> {
	value: T;
	id: string | number;
	disabled?: boolean;
}

export interface SelectPropsBase<T> {
	/**
	 * Callback fired when the component requests to be closed.
	 */
	onClose?: () => void;
	/**
	 * Callback fired when the component requests to be opened.
	 */
	onOpen?: () => void;
	/**
	 * If `true`, the component is shown.
	 */
	open?: boolean;
	/**
	 * Render the selected value.
	 */
	renderValue?: (values: T[]) => string;
	/** ClassName of dropdown menu */
	dropdownClassName?: string;

	/**
	 * Enabling multiple selections.
	 * @default false
	 */
	multiple?: boolean;
	/**
	 * Enabling filter.
	 *
	 */
	filterPlaceholder?: string;
	/**
	 * Custom filter function.
	 * @default false
	 */
	filterFunction?: (options: Array<Option<T>>, filterValue: string) => Array<Option<T>>;
	/**
	 * Callback fired when a menu item is selected.
	 *
	 * @param {Array<SelectItem>} values The array of selected values.
	 * @param {SelectItem} changedItem  Return changed element if multiselect is true. Null if multiselect is false.
	 */
	onChange: (values: T[], changedItem?: T) => void;
	/**
	 * Опции селекта
	 *
	 * Если передать массив строк или объектов с свойством value - сработает дефолтный рендерер
	 * Если вы хотите управлять отрисовкой опций - воспользуйтесь пропсом {@link makeOption}
	 */
	options: T[];
	/**
	 * Selected options.
	 */
	values: T[];

	/**
	 * Если передан, то внутренние обработчики клика по опции не сработают,
	 * вместо этого управление опциями осуществляется в родительском компоненте
	 */
	onManualClickOption?: (option: T) => void;

	onOutsideClick?: () => void;
	/**
	 * Making views of option elements
	 */
	makeOption?: (option: T, selected?: boolean) => React.JSX.Element;
	loading?: boolean;

	/**
	 * @deprecated
	 * Будет удалено в следующих релизах, используйте loadingContent
	 */
	loadingText?: string | React.ReactNode;

	loadingContent?: string | React.ReactNode;
	/**
	 *  The ID of the element where the dropdown menu will be mounted.
	 */
	applicationRootElementID?: string;
	/**
	 * The ID with which to be created the dropdown menu.
	 */
	dropdownElementID?: string;
	/**
	 * Показывать тултип, если содержание польше чем размер поля (по умолчанию true).
	 */
	showTooltip?: boolean;
	/**
	 * Текст отображаемый при пустом поиске.
	 */
	noOptionsText?: string;
	/**
	 * Альтернативный текст для чекбокса: "Выбрать все"
	 */
	selectAllText?: string;
	/**
	 * Включить/отключить навигацию клавиатуры
	 */
	enableKeyboardNavigation?: boolean;
	/**
	 * Показывает количество выбранных значений в селекте, при multiple = true
	 */
	isShowCountOfValues?: boolean;

	/**
	 * Фильтр вкл/выкл
	 */
	filter?: boolean;
	/**
	 * Опция "Выбрать все"
	 */
	selectAll?: boolean;
	/**
	 * Определяет, должно ли наложение блокировать прокрутку на теле документа.
	 * @default true
	 */
	overlayScroll?: boolean;
	/**
	 * Указывает, нужно ли рендерить оверлей
	 * */
	shouldRenderOverlay?: boolean;
	/**
	 * Добавляет className для Overlay
	 * */
	overlayClassName?: string;
	/**
	 * Выравнивание дропдавна
	 * */
	alignDropDown?: Placement;
	/** Кастомный компонент для обертки элемента */
	makeOptionWrapper?: (
		option: T,
		selected?: boolean /** Стандартные пропсы компонента */,
		defaultProps?: {
			key: string | number;
			className: string;
			onClick: () => void;
			children: React.JSX.Element;
		},
	) => React.JSX.Element;
	/**
	 * Определяет, как сравнивать объекты при выборе опций.
	 * Может быть строкой (ключом объекта) или функцией сравнения.
	 *
	 * @example
	 * // Сравнение по полю id
	 * compareBy="id"
	 *
	 * @example
	 * // Кастомная функция сравнения
	 * compareBy={(a, b) => a.id === b.id && a.version === b.version}
	 */
	compareBy?: string | ((a: T, b: T) => boolean);
	/**
	 * Скрывает выпадающее меню, даже если состояние open равно true
	 * @default false
	 */
	hideDropDown?: boolean;

	/**
	 * Отключает использование BottomSheet на мобильных устройствах
	 * @default false
	 */
	disableMobileBottomSheet?: boolean;

	/**
	 * Список групп
	 */
	groups?: Array<Option<string>>;
}

export enum CheckboxType {
	UNCHECKED,
	PARTIALLY,
	CHECKED,
}

export type SelectProps<T> = TextFieldPropsOmit & SelectPropsBase<T> & TestComponentProps;
